class Solution(object):
    def captureForts(self, forts):
        max_capture = 0
        count = 0
        last_fort = None
        for f in forts:
            if f != 0:
                if last_fort is not None and last_fort != f:
                    max_capture = max(max_capture, count)
                count = 0
                last_fort = f
            elif last_fort is not None:
                count += 1
        return max_capture
